// Package scraper provides browser automation and caching infrastructure for
// scraping admissions deadline data from college application platforms.
package scraper

import (
	"context"
	"fmt"
	"log/slog"
	"time"

	"github.com/chromedp/chromedp"
)

// Browser wraps a headless Chrome instance via chromedp for scraping pages
// that require JavaScript execution.
type Browser struct {
	allocCtx    context.Context
	allocCancel context.CancelFunc
	timeout     time.Duration
	retries     int
}

// Option configures Browser behaviour.
type Option func(*browserConfig)

type browserConfig struct {
	headless  bool
	width     int
	height    int
	userAgent string
	timeout   time.Duration
	retries   int
}

func defaultConfig() browserConfig {
	return browserConfig{
		headless:  true,
		width:     1920,
		height:    1080,
		userAgent: "",
		timeout:   30 * time.Second,
		retries:   2,
	}
}

// WithHeadless sets whether Chrome runs in headless mode (default: true).
func WithHeadless(headless bool) Option {
	return func(c *browserConfig) { c.headless = headless }
}

// WithViewport sets the browser viewport dimensions.
func WithViewport(width, height int) Option {
	return func(c *browserConfig) {
		c.width = width
		c.height = height
	}
}

// WithUserAgent overrides the default browser user agent string.
func WithUserAgent(ua string) Option {
	return func(c *browserConfig) { c.userAgent = ua }
}

// WithTimeout sets the per-call timeout for navigation and evaluation
// (default: 30s).
func WithTimeout(d time.Duration) Option {
	return func(c *browserConfig) { c.timeout = d }
}

// WithRetries sets the number of retry attempts for transient failures
// (default: 2).
func WithRetries(n int) Option {
	return func(c *browserConfig) { c.retries = n }
}

// New launches a headless Chrome instance and returns a Browser. The caller
// must call Close when finished to release browser resources.
func New(opts ...Option) (*Browser, error) {
	cfg := defaultConfig()
	for _, opt := range opts {
		opt(&cfg)
	}

	allocOpts := append(
		chromedp.DefaultExecAllocatorOptions[:],
		chromedp.Flag("headless", cfg.headless),
		chromedp.WindowSize(cfg.width, cfg.height),
	)
	if cfg.userAgent != "" {
		allocOpts = append(allocOpts, chromedp.UserAgent(cfg.userAgent))
	}

	allocCtx, allocCancel := chromedp.NewExecAllocator(context.Background(), allocOpts...)

	// Create a browser context to verify Chrome launches successfully.
	testCtx, testCancel := chromedp.NewContext(allocCtx)
	defer testCancel()

	verifyCtx, verifyCancel := context.WithTimeout(testCtx, 10*time.Second)
	defer verifyCancel()

	if err := chromedp.Run(verifyCtx); err != nil {
		allocCancel()
		return nil, fmt.Errorf("scraper: launch chrome: %w", err)
	}

	return &Browser{
		allocCtx:    allocCtx,
		allocCancel: allocCancel,
		timeout:     cfg.timeout,
		retries:     cfg.retries,
	}, nil
}

// Navigate loads the given URL and waits for the network to become idle.
// It respects the browser's configured timeout and retry settings.
func (b *Browser) Navigate(ctx context.Context, url string) error {
	var lastErr error
	for attempt := 0; attempt <= b.retries; attempt++ {
		if attempt > 0 {
			slog.Debug("scraper: retrying navigation", "url", url, "attempt", attempt)
		}

		lastErr = b.doNavigate(ctx, url)
		if lastErr == nil {
			return nil
		}

		// Don't retry if the parent context is cancelled.
		if ctx.Err() != nil {
			return fmt.Errorf("scraper: navigate %s: %w", url, ctx.Err())
		}
	}
	return fmt.Errorf("scraper: navigate %s after %d attempts: %w", url, b.retries+1, lastErr)
}

func (b *Browser) doNavigate(ctx context.Context, url string) error {
	tabCtx, tabCancel := chromedp.NewContext(b.allocCtx)
	defer tabCancel()

	timeoutCtx, timeoutCancel := context.WithTimeout(tabCtx, b.timeout)
	defer timeoutCancel()

	// Merge the caller's context cancellation.
	go func() {
		select {
		case <-ctx.Done():
			tabCancel()
		case <-timeoutCtx.Done():
		}
	}()

	return chromedp.Run(timeoutCtx,
		chromedp.Navigate(url),
		chromedp.WaitReady("body"),
	)
}

// EvalStrings evaluates a JavaScript expression that returns an array of
// strings in a new browser tab. The expression must evaluate to a JS array
// (e.g. `[...document.querySelectorAll('a')].map(e => e.textContent)`).
func (b *Browser) EvalStrings(ctx context.Context, jsExpr string) ([]string, error) {
	var lastErr error
	for attempt := 0; attempt <= b.retries; attempt++ {
		if attempt > 0 {
			slog.Debug("scraper: retrying eval", "attempt", attempt)
		}

		result, err := b.doEvalStrings(ctx, jsExpr)
		if err == nil {
			return result, nil
		}
		lastErr = err

		if ctx.Err() != nil {
			return nil, fmt.Errorf("scraper: eval: %w", ctx.Err())
		}
	}
	return nil, fmt.Errorf("scraper: eval after %d attempts: %w", b.retries+1, lastErr)
}

func (b *Browser) doEvalStrings(ctx context.Context, jsExpr string) ([]string, error) {
	tabCtx, tabCancel := chromedp.NewContext(b.allocCtx)
	defer tabCancel()

	timeoutCtx, timeoutCancel := context.WithTimeout(tabCtx, b.timeout)
	defer timeoutCancel()

	go func() {
		select {
		case <-ctx.Done():
			tabCancel()
		case <-timeoutCtx.Done():
		}
	}()

	var result []string
	if err := chromedp.Run(timeoutCtx,
		chromedp.Evaluate(jsExpr, &result),
	); err != nil {
		return nil, fmt.Errorf("scraper: evaluate js: %w", err)
	}

	return result, nil
}

// Close shuts down the Chrome allocator and releases all browser resources.
func (b *Browser) Close() {
	b.allocCancel()
}
